    try {
      await fetch('/api/contact', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ type: 'booking', program: selected, locale: lang, ...form, timestamp: new Date().toISOString() }),
      })
    } catch {}
    setSubmitted(true)
