# Expected valid keys per page section (based on ES)
VALID_HOME_KEYS = {"hero", "trust", "services", "whyCountry", "process", "feedback", "finalCta", "seo"}
VALID_HOURS_KEYS = {"Lun–Vie", "Sáb", "Dom", "Mon–Fri", "Sat", "Sun", "Ma–Vr", "Za", "Zo", "Mo–Fr", "Sa", "So"}

for loc in ["en", "nl", "de"]:
    d = json.load(open(f"/root/nexa-paraguay/content/{loc}.json"))
    changed = False

    # Fix home: keep only VALID_HOME_KEYS
    if "home" in d and isinstance(d["home"], dict):
        polluted = set(d["home"].keys()) - VALID_HOME_KEYS
        if polluted:
            print(f"{loc}.json home: removing {len(polluted)} polluted keys: {sorted(polluted)[:5]}...")
            d["home"] = {k: v for k, v in d["home"].items() if k in VALID_HOME_KEYS}
            changed = True

    # Fix contactPage.contact.hours
    contact = d.get("contactPage", {}).get("contact", {})
    if isinstance(contact.get("hours"), dict):
        hours_polluted = set(contact["hours"].keys()) - VALID_HOURS_KEYS
        if hours_polluted:
            print(f"{loc}.json contactPage.contact.hours: removing {len(hours_polluted)} polluted keys")
            contact["hours"] = {k: v for k, v in contact["hours"].items() if k in VALID_HOURS_KEYS}
            changed = True

    # Also check any other object that has flat page keys leaked in
    # Check all nested objects that shouldn't have "aboutPage" etc.
    def clean_polluted_nested(obj, path=""):
        nonlocal changed
        if not isinstance(obj, dict):
            return obj
        # Check if this dict has page-level keys leaked
        page_keys = {"aboutPage", "beneluxPage", "blog", "caseStudiesPage", "comparisonPage", 
                    "complianceDisclaimer", "contactPage", "datosPersonalesPage", "faqPage",
                    "feedbackPage", "bookingPage", "footer", "founderPage", "glossaryPage",
                    "home", "intakeWizardPage", "landingEmpresa", "landingInversor",
                    "landingLifestyle", "landingTrust", "navigation", "placeholders",
                    "prensa", "privacyPage", "processPage", "programasPage", 
                    "qualityOfLifePage", "resourcesPage", "seo", "seprealadAttestation",
                    "servicesPage", "siteName", "tagline", "whatsapp", "whyCountryPage",
                    "processTeaser"}
        has_page_leak = any(k in obj for k in page_keys)
        if has_page_leak and path and not path.startswith("seo") and not path.startswith("footer"):
            # This dict has page keys leaked into it
            legit_keys = [k for k in obj if k not in page_keys]
            polluted = [k for k in obj if k in page_keys]
            if legit_keys and polluted:
                print(f"  {path}: {len(polluted)} leaked keys (keeping {len(legit_keys)} valid)")
                changed = True
                return {k: v for k, v in obj.items() if k not in page_keys}
        return obj

    def deep_clean(obj, path=""):
        if isinstance(obj, dict):
            obj = clean_polluted_nested(obj, path)
            return {k: deep_clean(v, f"{path}.{k}" if path else k) for k, v in obj.items()}
        elif isinstance(obj, list):
            return [deep_clean(item, f"{path}[{i}]") for i, item in enumerate(obj)]
        return obj

    d = deep_clean(d)

    if changed:
        json.dump(d, open(f"/root/nexa-paraguay/content/{loc}.json", "w"), indent=2, ensure_ascii=False)
        print(f"  → Saved {loc}.json\n")
    else:
        print(f"{loc}.json: no pollution found\n")
"}

